// --- Timing Konstanten (basierend auf 8MHz RMT Clock -> 125ns/Tick) ---
#define TICK_1T       32  // 4us (Half-Bit / Chip)
#define TICK_2T       64  // 8us (Full-Bit)
#define TICK_3_4      48  // 6us (Sample Point)

// Toleranzen für SOF-Erkennung
#define MIN_1T        14
#define MAX_1T        48
#define MIN_2T        49
#define MAX_2T        85
#define NOISE_RESET   100 // Ticks für Timeout/Noise (12.5us)

typedef enum {
    ERP1_STATE_SYNC,
    ERP1_STATE_SOF_WAIT_HIGH,
    ERP1_STATE_DATA
} erp1_state_t;

typedef struct {
    erp1_state_t state;
    int sync_pulses;

    // Clock Recovery (PLL)
    int t_accum;
    int next_sample;

    // Data Buffer
    uint8_t buffer[32];
    int byte_idx;
    int bit_idx;
    uint8_t current_byte;

    bool packet_ready; // Flag, wenn ein Paket komplett ausgewertet wurde
} erp1_decoder_t;

// Initialisiert oder resettet den Decoder
void erp1_decoder_reset(erp1_decoder_t *dec) {
    dec->state = ERP1_STATE_SYNC;
    dec->sync_pulses = 0;
    dec->byte_idx = 0;
    dec->bit_idx = 0;
    dec->current_byte = 0;
    dec->packet_ready = false;
}

// Interne Funktion: Bit ins Array schieben
static void push_bit(erp1_decoder_t *dec, uint8_t bit) {
    dec->current_byte = (dec->current_byte << 1) | (bit & 0x01);
    dec->bit_idx++;

    if (dec->bit_idx == 8) {
        if (dec->byte_idx < sizeof(dec->buffer)) {
            dec->buffer[dec->byte_idx++] = dec->current_byte;
        }
        dec->bit_idx = 0;
        dec->current_byte = 0;
    }
}

// Interne Funktion: Prüft die Checksumme am Ende der Übertragung
static void evaluate_packet(erp1_decoder_t *dec) {
    // Ein minimales ERP1 Paket (z.B. RPS) hat 7 Bytes + 1 Byte Checksum = 8 Bytes
    if (dec->byte_idx >= 7) {
        uint8_t sum = 0;
        // Checksumme ist die simple Modulo-256 Summe aller Bytes VOR der Checksumme
        for (int i = 0; i < dec->byte_idx - 1; i++) {
            sum += dec->buffer[i];
        }

        if (sum == dec->buffer[dec->byte_idx - 1]) {
            dec->packet_ready = true; // Gültiges Paket im Buffer!
        }
    }
}

// Hauptfunktion: Verarbeitet einen einzelnen RMT-Puls (Level und Dauer)
void erp1_decode_pulse(erp1_decoder_t *dec, int level, int duration) {
    // Noise oder Gap detektiert -> Paket ist zu Ende, auswerten und Reset
    if (duration > NOISE_RESET) {
        if (dec->state == ERP1_STATE_DATA) {
            evaluate_packet(dec);
        }
        if (!dec->packet_ready) erp1_decoder_reset(dec);
        return;
    }

    switch (dec->state) {
        case ERP1_STATE_SYNC:
            if (duration >= MIN_1T && duration <= MAX_1T) {
                dec->sync_pulses++; // Präambel (4us Pulse)
            } 
            else if (duration >= MIN_2T && duration <= MAX_2T && level == 0 && dec->sync_pulses >= 6) {
                // 8us LOW detektiert UND vorher genug Präambel gesehen -> SOF Transition
                dec->state = ERP1_STATE_SOF_WAIT_HIGH;
            } 
            else {
                dec->sync_pulses = 0; // Fehlerhafter Puls -> Reset Sync
            }
            break;

        case ERP1_STATE_SOF_WAIT_HIGH:
            // Nach dem 8us LOW muss zwingend ein 4us HIGH kommen, um das SOF-Bit ('0') abzuschließen
            if (level == 1 && duration >= MIN_1T && duration <= MAX_1T) {
                dec->state = ERP1_STATE_DATA;
                dec->t_accum = 0;
                dec->next_sample = TICK_3_4; // Erster Sample-Punkt bei 3/4 des Bits (48 Ticks)
                dec->byte_idx = 0;
                dec->bit_idx = 0;
                dec->current_byte = 0;
            } else {
                erp1_decoder_reset(dec);
            }
            break;

        case ERP1_STATE_DATA: {
            // --- PLL Clock Recovery ---
            // Das ideale Bit-Center (Flanke) liegt genau 16 Ticks VOR unserem 3/4 Sample-Punkt
            int expected_center = dec->next_sample - (TICK_1T / 2);
            int edge_time = dec->t_accum + duration; // Absolute Zeit DIESER Flanke

            // Wenn diese Flanke in der Nähe des erwarteten Centers liegt (Toleranz +- 12 Ticks)
            if (abs(edge_time - expected_center) < 12) {
                int error = edge_time - expected_center;
                // PLL-Filter: Korrigiere den nächsten Sample-Point um 25% des Fehlers (IIR)
                dec->next_sample += error / 4; 
            }

            // Zeit-Akkumulator vorschieben
            dec->t_accum += duration;

            // Haben wir einen oder mehrere Sample-Punkte überschritten?
            while (dec->t_accum >= dec->next_sample) {
                // Bei 3/4 des Bits lesen wir das Level aus.
                // Da `t_accum` >= `next_sample` ist, befand sich das Signal an `next_sample` auf `level`.
                // EnOcean Manchester: '1' endet LOW (0). '0' endet HIGH (1).
                uint8_t bit = (level == 0) ? 1 : 0;
                push_bit(dec, bit);

                // Zum nächsten Bit springen (+8us)
                dec->next_sample += TICK_2T;
            }
            break;
        }
    }
}
```

### 4. Integration mit dem ESP32-C6 RMT Driver (Multi-Block Handling)

Der ESP-IDF 5.x RMT-Treiber nutzt DMA und Ringpuffer. In deinem `rmt_rx_done_callback` oder deiner Haupt-Task erhältst du ein Array von `rmt_symbol_word_t`.
Da der Payload größer sein kann als der RMT-Hardware-Speicher, liefert dir der Treiber die Daten ggf. in mehreren Chunks. 

**So behandelst du das elegant:**
Da unsere `erp1_decoder_t` State Machine als Kontext existiert, behält sie ihren Zustand nahtlos zwischen zwei Speicherblöcken. Du musst das Array einfach nur linear durchschleifen:

```c
// Globale oder Task-lokale Decoder Instanz
erp1_decoder_t decoder;

void process_rmt_symbols(rmt_symbol_word_t *symbols, size_t num_symbols) {
    for (size_t i = 0; i < num_symbols; i++) {
        // Ein RMT Symbol in ESP-IDF enthält immer ZWEI Pulse (Level + Duration Paare)

        // Puls 0
        erp1_decode_pulse(&decoder, symbols[i].level0, symbols[i].duration0);
        if (decoder.packet_ready) {
            handle_valid_packet(decoder.buffer, decoder.byte_idx);
            erp1_decoder_reset(&decoder);
        }

        // Puls 1
        erp1_decode_pulse(&decoder, symbols[i].level1, symbols[i].duration1);
        if (decoder.packet_ready) {
            handle_valid_packet(decoder.buffer, decoder.byte_idx);
            erp1_decoder_reset(&decoder);
        }
    }
}
```

### 5. Zusammenfassung der Architektur-Vorteile
1. **Zentrum-Sampling (3/4-Regel):** Wir werten nicht jede Pulslänge als Bit aus. Ein auf 5µs gestrecktes HIGH und 3µs geschrumpftes LOW (typisch bei CC1101) wirft klassische Decoder aus dem Tritt. Da wir strikt bei 6µs (48 Ticks) samplen, sind wir gegen extreme Duty-Cycle-Verzerrungen bis zu ±30% immun.
2. **Missing Pulses:** Wenn das Signal durch extrem kurzes Fading kurz ausfällt und keine Flanke generiert, rechnet die `while (dec->t_accum >= dec->next_sample)` Schleife das Bit stur anhand der akkumulierten Zeit und des zuletzt anliegenden Pegels weiter.
3. **Multi-Chunk-Fähigkeit:** Das Design trennt den Buffer-Status komplett vom RMT-Hardware-Timing. Das RMT-Memory Array kann exakt in der Mitte eines Bits enden – der State `t_accum` friert diesen Moment ein und macht im nächsten Block nahtlos weiter.

